'use client';

import Image from 'next/image';
import { Avatar, Button, Group, Text } from '@mantine/core';
import { useDisclosure } from '@mantine/hooks';
import { AuthModal } from '@/src/components/AuthModal/AuthModal';
import classes from './Header.module.css';
import { useUserStore } from '@/src/store/user-store';
import { redirect } from 'next/navigation'

export function Header() {
  const {
    profile
  } = useUserStore()
  const [authModalOpened, { open: openAuthModal, close: closeAuthModal }] = useDisclosure(false);

  function handleAuthenticated () {
    closeAuthModal()
    redirect('/dashboard')
  }

  return (
    <header className={classes.header}>
      <Group justify="space-between" className={classes.headergrp}>
        <Group gap="xs">
          <Image src="/icon.png" alt="fold.ly" width={28} height={28} />
          <Text className={classes.logo} size="lg">
            fold<Text inherit component="span" c="yellow.5">.ly</Text>
          </Text>
        </Group>
        {
          profile
            ? (
              <Avatar
                src={profile.profile_pic || "/empty_profile_img.png"} alt={profile.name} />
            ) : (
              <Button size="sm" onClick={openAuthModal}>
                Sign in
              </Button>
            )
        }
      </Group>

      <AuthModal
        opened={authModalOpened}
        onAuthenticated={handleAuthenticated}
        onClose={closeAuthModal}
        initialMode="login"
      />
    </header>
  );
}
